export default {
  name: "Simple Table",
  description: "A basic data table with striped rows",
  category: "data",
};

export default function SimpleTable() {
  const data = [
    { id: 1, name: "John Doe", email: "john@example.com", role: "Admin" },
    { id: 2, name: "Jane Smith", email: "jane@example.com", role: "User" },
    { id: 3, name: "Bob Johnson", email: "bob@example.com", role: "User" },
  ];

  return (
    <table
      style={{
        width: "100%",
        borderCollapse: "collapse",
        fontSize: "0.875rem",
      }}
    >
      <thead>
        <tr style={{ backgroundColor: "#f3f4f6" }}>
          <th
            style={{
              padding: "0.75rem",
              textAlign: "left",
              fontWeight: "600",
              color: "#374151",
            }}
          >
            Name
          </th>
          <th
            style={{
              padding: "0.75rem",
              textAlign: "left",
              fontWeight: "600",
              color: "#374151",
            }}
          >
            Email
          </th>
          <th
            style={{
              padding: "0.75rem",
              textAlign: "left",
              fontWeight: "600",
              color: "#374151",
            }}
          >
            Role
          </th>
        </tr>
      </thead>
      <tbody>
        {data.map((row, index) => (
          <tr
            key={row.id}
            style={{
              backgroundColor: index % 2 === 0 ? "white" : "#f9fafb",
            }}
          >
            <td style={{ padding: "0.75rem", color: "#111827" }}>
              {row.name}
            </td>
            <td style={{ padding: "0.75rem", color: "#6b7280" }}>
              {row.email}
            </td>
            <td style={{ padding: "0.75rem", color: "#6b7280" }}>
              {row.role}
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

export default {
  name: "Hero Section",
  description: "A centered hero section with title and CTA",
  category: "layout",
};

export default function HeroSection() {
  return (
    <div
      style={{
        textAlign: "center",
        padding: "4rem 2rem",
        backgroundColor: "#f9fafb",
      }}
    >
      <h1
        style={{
          fontSize: "3rem",
          fontWeight: "bold",
          margin: "0 0 1rem 0",
          color: "#111827",
        }}
      >
        Welcome to Our Platform
      </h1>
      <p
        style={{
          fontSize: "1.25rem",
          color: "#6b7280",
          margin: "0 0 2rem 0",
          maxWidth: "600px",
          marginLeft: "auto",
          marginRight: "auto",
        }}
      >
        Build amazing things with our powerful tools and components
      </p>
      <button
        style={{
          padding: "0.875rem 2rem",
          backgroundColor: "#3b82f6",
          color: "white",
          border: "none",
          borderRadius: "0.5rem",
          fontSize: "1.125rem",
          fontWeight: "600",
          cursor: "pointer",
        }}
      >
        Get Started
      </button>
    </div>
  );
}

export default {
  name: "Success Toast",
  description: "A success notification toast message",
  category: "feedback",
};

export default {
  name: "Simple Navbar",
  description: "A basic navigation bar with logo and links",
  category: "navigation",
};
